// HMAC Signature Verification
// This node validates that the request came from an authorized source

const crypto = require('crypto');

// Get the HMAC secret from credentials (stored securely in n8n)
const HMAC_SECRET = $credentials.webhookHmacSecret ? $credentials.webhookHmacSecret.secret : process.env.WEBHOOK_HMAC_SECRET;

if (!HMAC_SECRET) {
  throw new Error('HMAC_SECRET not configured. Please set up webhookHmacSecret credential or WEBHOOK_HMAC_SECRET environment variable.');
}

// Get the signature from headers
const signature = $input.first().json.headers['x-webhook-signature'] || 
                  $input.first().json.headers['X-Webhook-Signature'];

if (!signature) {
  throw new Error('Missing X-Webhook-Signature header. Request rejected.');
}

// Get the body for signature verification
const body = $input.first().json.body;

// Verify timestamp to prevent replay attacks (optional but recommended)
const timestamp = $input.first().json.headers['x-webhook-timestamp'] || 
                  $input.first().json.headers['X-Webhook-Timestamp'];

if (timestamp) {
  const requestTime = parseInt(timestamp, 10);
  const currentTime = Math.floor(Date.now() / 1000);
  const tolerance = 300; // 5 minutes tolerance

  if (Math.abs(currentTime - requestTime) > tolerance) {
    throw new Error('Request timestamp too old. Possible replay attack.');
  }
}

// Compute expected signature
const payload = JSON.stringify(body);
const expectedSignature = crypto
  .createHmac('sha256', HMAC_SECRET)
  .update(payload)
  .digest('hex');

// Constant-time comparison to prevent timing attacks
const providedSigBuffer = Buffer.from(signature, 'hex');
const expectedSigBuffer = Buffer.from(expectedSignature, 'hex');

let isValid = false;
try {
  isValid = providedSigBuffer.length === expectedSigBuffer.length && 
            crypto.timingSafeEqual(providedSigBuffer, expectedSigBuffer);
} catch (e) {
  isValid = false;
}

if (!isValid) {
  throw new Error('Invalid HMAC signature. Request rejected.');
}

// HMAC verified - return the body for processing
return [{
  json: {
    verified: true,
    data: body
  }
}];

