// Parse form data and prepare for CRM
const input = $input.first().json.data;

// Validate required fields
if (!input.name || !input.email || !input.company) {
  throw new Error('Missing required fields: name, email, or company');
}

// Split name into first and last
const nameParts = input.name.split(' ') || ['Unknown'];
const firstName = nameParts[0];
const lastName = nameParts.slice(1).join(' ') || '';

// Format techStack and compliance arrays
const techStack = Array.isArray(input.techStack) 
  ? input.techStack.join(', ') 
  : input.techStack || '';

const compliance = Array.isArray(input.compliance) 
  ? input.compliance.join(', ') 
  : input.compliance || '';

return [{
  json: {
    person: {
      firstName: firstName,
      lastName: lastName,
      email: input.email,
      jobTitle: input.role || ''
    },
    company: {
      name: input.company
    },
    note: {
      message: input.message || '',
      techStack: techStack,
      securityLevel: input.securityLevel || '',
      compliance: compliance,
      teamSize: input.teamSize || '',
      submittedAt: new Date().toISOString()
    }
  }
}];

